script:
frappe.ui.form.on('Daily Call Report', {

    employee: function(frm) {
        if (!frm.doc.employee) return;
        frappe.db.get_value('Employee', frm.doc.employee, 'department', function(d) {
            if (!d || !d.department) return;
            var dept = d.department.toUpperCase();
            var detected = 'Office';
            if (dept.includes('SALES') || dept.includes('MARKETING') || dept.includes('BUSINESS')) {
                detected = 'Sales';
            } else if (dept.includes('SERVICE') || dept.includes('MAINTENANCE')) {
                detected = 'Service';
            }
            frm.set_value('department', detected);
            frappe.show_alert({message: 'Department set to: ' + detected, indicator: 'blue'});
        });
    },

    department: function(frm) {
        frm.set_value('visit_purpose', '');
        frm.set_value('service_purpose', '');
        frm.set_value('customer', '');
        frm.set_value('lead', '');
    },

    refresh: function(frm) {
        frm.add_custom_button(__('Check-In GPS'), function() {
            if (!navigator.geolocation) {
                frappe.msgprint('GPS not supported on this device/browser.');
                return;
            }
            frappe.show_alert({message: 'Getting your location...', indicator: 'blue'});
            navigator.geolocation.getCurrentPosition(
                function(pos) {
                    var coords = pos.coords.latitude.toFixed(6) + ', ' + pos.coords.longitude.toFixed(6);
                    frm.set_value('check_in_gps', coords);
                    if (!frm.doc.check_in_time) {
                        frm.set_value('check_in_time', frappe.datetime.now_datetime());
                    }
                    frm.save();
                    frappe.show_alert({message: 'Check-In captured!', indicator: 'green'});
                },
                function(err) { frappe.msgprint('Location error: ' + err.message); },
                {enableHighAccuracy: true, timeout: 10000}
            );
        }, __('GPS'));

        frm.add_custom_button(__('Check-Out GPS'), function() {
            if (!navigator.geolocation) {
                frappe.msgprint('GPS not supported on this device/browser.');
                return;
            }
            frappe.show_alert({message: 'Getting your location...', indicator: 'blue'});
            navigator.geolocation.getCurrentPosition(
                function(pos) {
                    var coords = pos.coords.latitude.toFixed(6) + ', ' + pos.coords.longitude.toFixed(6);
                    frm.set_value('check_out_gps', coords);
                    if (!frm.doc.check_out_time) {
                        frm.set_value('check_out_time', frappe.datetime.now_datetime());
                    }
                    frm.set_value('status', 'Completed');
                    frm.save();
                    frappe.show_alert({message: 'Check-Out captured!', indicator: 'green'});
                },
                function(err) { frappe.msgprint('Location error: ' + err.message); },
                {enableHighAccuracy: true, timeout: 10000}
            );
        }, __('GPS'));
    }
});
